// Import libraries
import Sequelize from "sequelize";
import { encrypt, decrypt } from "../lib/encryption.js";

/**
 * @swagger
 * components:
 *   schemas:
 *     Consumer:
 *       type: object
 *       required:
 *         - name
 *         - key
 *       properties:
 *         id:
 *           type: integer
 *           description: autogenerated id
 *         name:
 *           type: string
 *           description: name of the consumer
 *         lti13:
 *           type: boolean
 *           description: enabled if consumer uses LTI 1.3
 *         key:
 *           type: string
 *           description: the OAuth consumer key or LTI 1.3 unique URL path
 *         client_id:
 *           type: string
 *           description: the LTI 1.3 client ID
 *         platform_id:
 *           type: string
 *           description: the LTI 1.3 platform ID
 *         deployment_id:
 *           type: string
 *           description: the LTI 1.3 deployment ID
 *         keyset_url:
 *           type: string
 *           format: url
 *           description: the URL to request the JWKS
 *         token_url:
 *           type: string
 *           format: url
 *           description: the URL to request a token
 *         auth_url:
 *           type: string
 *           format: url
 *           description: the URL to redirect to for authentication
 *         tc_product:
 *           type: string
 *           description: the product name of the tool consumer
 *         tc_version:
 *           type: string
 *           description: the version of the tool consumer
 *         tc_guid:
 *           type: string
 *           description: the unique GUID of the tool consumer
 *         tc_name:
 *           type: string
 *           description: the internal name of the tool consumer
 *         createdAt:
 *           type: string
 *           format: date-time
 *           description: when the record was created
 *         updatedAt:
 *           type: string
 *           format: date-time
 *           description: when the record was last updated
 *       example:
 *           id: 1
 *           name: Canvas
 *           lti13: true
 *           key: abcdef12345
 *           client_id: 1000000000001
 *           platform_id: https://canvas.instructure.com
 *           deployment_id: superlongstringhere
 *           keyset_url: https://canvas.instructure.com/api/lti/security/jwks
 *           token_url: https://canvas.instructure.com/login/oauth2/token
 *           auth_url: https://canvas.instructure.com/api/lti/authorize_redirect
 *           createdAt: 2025-02-04T15:36:32.000Z
 *           updatedAt: 2025-02-04T15:36:32.000Z
 */
const ConsumerSchema = {
  id: {
    type: Sequelize.INTEGER,
    primaryKey: true,
    autoIncrement: true,
  },
  name: {
    type: Sequelize.STRING,
    unique: true,
    allowNull: false,
    // force null if empty string
    set(value) {
      this.setDataValue("name", value === "" ? null : value);
    },
  },
  lti13: {
    type: Sequelize.BOOLEAN,
    defaultValue: false,
  },
  key: {
    type: Sequelize.STRING,
    unique: true,
    allowNull: false,
  },
  client_id: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  platform_id: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  deployment_id: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  keyset_url: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  token_url: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  auth_url: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  tc_product: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  tc_version: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  tc_guid: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  tc_name: {
    type: Sequelize.STRING,
    allowNull: true,
  },
  createdAt: {
    type: Sequelize.DATE,
    allowNull: false,
  },
  updatedAt: {
    type: Sequelize.DATE,
    allowNull: false,
  },
};

// secret and private are encrypted at rest (AES-256-GCM) using the configured encryption_key
const ConsumerKeySchema = (encryptionKey) => ({
  key: {
    type: Sequelize.STRING,
    primaryKey: true,
    allowNull: false,
    // force null if empty string
    set(value) {
      this.setDataValue("key", value === "" ? null : value);
    },
  },
  secret: {
    // TEXT, not STRING: encrypted values and PEM keys exceed VARCHAR(255) on strict dialects (e.g. Postgres)
    type: Sequelize.TEXT,
    allowNull: false,
    // force null if empty string, otherwise encrypt before storing
    set(value) {
      this.setDataValue("secret", value === "" ? null : encrypt(value, encryptionKey));
    },
    get() {
      return decrypt(this.getDataValue("secret"), encryptionKey);
    },
  },
  public: {
    // TEXT, not STRING: PEM-encoded public keys exceed VARCHAR(255) on strict dialects (e.g. Postgres)
    type: Sequelize.TEXT,
    allowNull: true,
  },
  private: {
    // TEXT, not STRING: encrypted PEM-encoded private keys exceed VARCHAR(255) on strict dialects (e.g. Postgres)
    type: Sequelize.TEXT,
    allowNull: true,
    // force null if empty string, otherwise encrypt before storing
    set(value) {
      this.setDataValue(
        "private",
        value === "" || value === null || value === undefined ? null : encrypt(value, encryptionKey),
      );
    },
    get() {
      const value = this.getDataValue("private");
      return value ? decrypt(value, encryptionKey) : value;
    },
  },
});

