/**
 * @swagger
 * components:
 *   schemas:
 *     Provider:
 *       type: object
 *       required:
 *         - name
 *         - key
 *         - launch_url
 *         - domain
 *       properties:
 *         id:
 *           type: integer
 *           description: autogenerated id
 *         name:
 *           type: string
 *           description: name of the provider
 *         lti13:
 *           type: boolean
 *           description: enabled if provider uses LTI 1.3
 *         key:
 *           type: string
 *           description: the OAuth provider key or LTI 1.3 unique URL path
 *         launch_url:
 *           type: string
 *           format: url
 *           description: the URL to send a launch
 *         domain:
 *           type: string
 *           format: hostname
 *           description: the domain of the application
 *         custom:
 *           type: string
 *           format: json
 *           description: a JSON string of custom variables
 *         use_section:
 *           type: boolean
 *           description: flag to differentiate between LTI Tool Providers that may need different handling (not implemented within this library itself; available for applications built on this library to use as needed)
 *         client_id:
 *           type: string
 *           description: the LTI 1.3 client ID (LTI 1.3 only)
 *         deployment_id:
 *           type: string
 *           description: the LTI 1.3 deployment ID (LTI 1.3 only)
 *         keyset_url:
 *           type: string
 *           format: url
 *           description: the URL to request the JWKS (LTI 1.3 only)
 *         auth_url:
 *           type: string
 *           format: url
 *           description: the URL to redirect to for authentication (LTI 1.3 only)
 *         redirect_urls:
 *           type: string
 *           format: json
 *           description: a JSON string of allowed redirect URLs (LTI 1.3 only)
 *         scopes:
 *           type: string
 *           format: json
 *           description: a JSON string of scopes to request (LTI 1.3 only)
 *         claims:
 *           type: string
 *           format: json
 *           description: a JSON string of claims to request (LTI 1.3 only)
 *         createdAt:
 *           type: string
 *           format: date-time
 *           description: when the record was created
 *         updatedAt:
 *           type: string
 *           format: date-time
 *           description: when the record was last updated
 *       example:
 *           id: 1
 *           name: Learning Tool
 *           lti13: false
 *           key: abcdef12345
 *           launch_url: https://tool.domain/lti/12345abcdef
 *           domain: tool.domain
 *           createdAt: 2025-02-04T15:36:32.000Z
 *           updatedAt: 2025-02-04T15:36:32.000Z
 */
